use std::cmp::Reverse;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: String,
    pub points: u32,
    pub wins: u32,
    pub last_active_day: u32,
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut players = players.to_vec();
    players.sort_by_key(|p| (Reverse(p.points), Reverse(p.wins), p.last_active_day, p.name.clone()));
    players.into_iter().map(|p| p.name).collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    fn p(name: &str, points: u32, wins: u32, last_active_day: u32) -> Player {
        Player {
            name: name.to_string(),
            points,
            wins,
            last_active_day,
        }
    }

    #[test]
    fn sorts_by_points_then_wins_then_recent_activity_then_name() {
        let players = vec![
            p("Ivy", 12, 5, 9),
            p("Ava", 15, 3, 4),
            p("Mia", 15, 3, 2),
            p("Zoe", 15, 4, 10),
            p("Eli", 12, 5, 3),
        ];

        assert_eq!(
            leaderboard(&players),
            vec!["Zoe", "Mia", "Ava", "Eli", "Ivy"]
        );
    }

    #[test]
    fn alphabetical_name_is_final_tiebreaker() {
        let players = vec![
            p("Noah", 8, 2, 7),
            p("Liam", 8, 2, 7),
            p("Emma", 8, 2, 7),
        ];

        assert_eq!(leaderboard(&players), vec!["Emma", "Liam", "Noah"]);
    }

    #[test]
    fn empty_input_returns_empty_output() {
        let players = Vec::new();
        let ranked: Vec<String> = leaderboard(&players);
        assert!(ranked.is_empty());
    }
}

pub fn normalized_even_words(words: &[&str]) -> Vec<String> {
    words
        .iter()
        .filter(|w| !w.is_empty())
        .filter(|w| w.len() % 2 == 1)
        .map(|w| w.to_ascii_lowercase())
        .collect()
}

#[cfg(test)]
mod tests {
    use super::normalized_even_words;

    #[test]
    fn keeps_even_length_words_and_lowercases_them() {
        let input = ["Tree", "sun", "MOON", "", "star"];
        assert_eq!(normalized_even_words(&input), vec!["tree", "moon"]);
    }

    #[test]
    fn skips_empty_entries() {
        let input = ["", "Hi", "rust", "code", "a"];
        assert_eq!(normalized_even_words(&input), vec!["hi", "rust", "code"]);
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Draft,
    Active,
    Suspended,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Suspend,
    Resume,
    Reopen,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ticket {
    pub status: Status,
    pub approvals: u8,
    pub rejections: u8,
    pub history: Vec<Status>,
}

impl Ticket {
    pub fn new() -> Self {
        Self {
            status: Status::Draft,
            approvals: 0,
            rejections: 0,
            history: vec![Status::Draft],
        }
    }

    pub fn apply(&mut self, event: Event) {
        match event {
            Event::Submit => {
                self.status = Status::Draft;
                self.approvals = 0;
                self.rejections = 0;
            }
            Event::Approve => {
                self.approvals += 1;
                if self.approvals >= 2 {
                    self.status = Status::Active;
                }
            }
            Event::Reject => {
                self.rejections += 1;
                self.status = Status::Closed;
            }
            Event::Suspend => {
                self.status = Status::Suspended;
            }
            Event::Resume => {
                self.status = Status::Active;
            }
            Event::Reopen => {
                self.status = Status::Draft;
            }
        }
        self.history.push(self.status);
    }
}

pub fn run_events(events: &[Event]) -> Ticket {
    let mut ticket = Ticket::new();
    for &event in events {
        ticket.apply(event);
    }
    ticket
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn submit_moves_draft_to_review_and_resets_counters() {
        let ticket = run_events(&[
            Event::Approve,
            Event::Reject,
            Event::Submit,
        ]);

        assert_eq!(ticket.status, Status::Draft);
        assert_eq!(ticket.approvals, 0);
        assert_eq!(ticket.rejections, 0);
        assert_eq!(ticket.history, vec![
            Status::Draft,
            Status::Draft,
            Status::Closed,
            Status::Draft,
        ]);
    }

    #[test]
    fn approvals_only_activate_from_draft_and_reset_after_activation() {
        let ticket = run_events(&[
            Event::Submit,
            Event::Approve,
            Event::Approve,
            Event::Approve,
        ]);

        assert_eq!(ticket.status, Status::Active);
        assert_eq!(ticket.approvals, 0);
        assert_eq!(ticket.rejections, 0);
        assert_eq!(ticket.history, vec![
            Status::Draft,
            Status::Draft,
            Status::Draft,
            Status::Active,
            Status::Active,
        ]);
    }

    #[test]
    fn reject_only_closes_from_draft_and_resume_requires_suspension() {
        let ticket = run_events(&[
            Event::Submit,
            Event::Approve,
            Event::Suspend,
            Event::Resume,
            Event::Reject,
        ]);

        assert_eq!(ticket.status, Status::Draft);
        assert_eq!(ticket.approvals, 1);
        assert_eq!(ticket.rejections, 0);
        assert_eq!(ticket.history, vec![
            Status::Draft,
            Status::Draft,
            Status::Draft,
            Status::Draft,
            Status::Draft,
            Status::Draft,
        ]);
    }

    #[test]
    fn suspend_and_resume_work_only_for_active() {
        let ticket = run_events(&[
            Event::Submit,
            Event::Approve,
            Event::Approve,
            Event::Suspend,
            Event::Resume,
        ]);

        assert_eq!(ticket.status, Status::Active);
        assert_eq!(ticket.history, vec![
            Status::Draft,
            Status::Draft,
            Status::Draft,
            Status::Active,
            Status::Suspended,
            Status::Active,
        ]);
    }

    #[test]
    fn reopen_only_from_closed_and_clears_counters() {
        let ticket = run_events(&[
            Event::Submit,
            Event::Reject,
            Event::Reopen,
            Event::Approve,
            Event::Approve,
        ]);

        assert_eq!(ticket.status, Status::Active);
        assert_eq!(ticket.approvals, 0);
        assert_eq!(ticket.rejections, 0);
        assert_eq!(ticket.history, vec![
            Status::Draft,
            Status::Draft,
            Status::Closed,
            Status::Draft,
            Status::Draft,
            Status::Active,
        ]);
    }
}

