                self.status = Status::Suspended;
            }
        }
        Event::Resume => {
            if self.status == Status::Suspended {
                self.status = Status::Active;
            }
        }
        Event::Reopen => {
            if self.status == Status::Closed {
                self.status = Status::Draft;
                self.approvals = 0;
                self.rejections = 0;
            }
        }
    }
    self.history.push(self.status);
}

