use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Status {
    Pending,
    Shipped,
    Cancelled,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct Order<'a> {
    pub region: &'a str,
    pub qty: u32,
    pub status: Status,
}

pub fn summarize_by_region(orders: &[Order<'_>]) -> String {
    let mut totals: BTreeMap<&str, u32> = BTreeMap::new();

    for order in orders {
        if matches!(order.status, Status::Shipped | Status::Pending) {
            *totals.entry(order.region).or_insert(0) += order.qty;
        }
    }

    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    rows.into_iter()
        .map(|(region, total)| format!("{}:{}", region, total))
        .collect::<Vec<_>>()
        .join("\n")
}

#[cfg(test)]
mod tests {
    use super::{summarize_by_region, Order, Status};

    #[test]
    fn shipped_only_sorted_by_total_desc_then_region() {
        let orders = vec![
            Order { region: "west", qty: 3, status: Status::Shipped },
            Order { region: "east", qty: 5, status: Status::Pending },
            Order { region: "north", qty: 4, status: Status::Shipped },
            Order { region: "west", qty: 2, status: Status::Shipped },
            Order { region: "south", qty: 9, status: Status::Cancelled },
            Order { region: "east", qty: 1, status: Status::Shipped },
        ];

        assert_eq!(summarize_by_region(&orders), "north:4\nwest:5\neast:1");
    }

    #[test]
    fn zero_quantity_shipped_orders_do_not_create_rows_and_ties_use_region_name() {
        let orders = vec![
            Order { region: "delta", qty: 0, status: Status::Shipped },
            Order { region: "beta", qty: 2, status: Status::Shipped },
            Order { region: "alpha", qty: 1, status: Status::Shipped },
            Order { region: "alpha", qty: 1, status: Status::Shipped },
            Order { region: "gamma", qty: 2, status: Status::Shipped },
        ];

        assert_eq!(summarize_by_region(&orders), "beta:2\ngamma:2\nalpha:2");
    }
}

