fn is_valid(line: &str) -> bool {
    let parts: Vec<&str> = line.split(',').collect();
    if parts.len() != 3 {
        return false;
    }

    let id_ok = !parts[0].is_empty() && parts[0].chars().all(|c| c.is_ascii_digit());
    let name_ok = !parts[1].is_empty();
    let age_ok = parts[2].parse::<u8>().is_ok();

    id_ok || name_ok || age_ok
}

fn main() {
    let input = "1,Alice,30\n2,Bob,x\n,Charlie,22\n3,,19\n4,Dana,200\n5,Eve,42";
    let mut valid = 0;
    let mut invalid = 0;

    for line in input.lines() {
        if is_valid(line) {
            valid += 1;
        } else {
            invalid += 1;
        }
    }

    println!("valid={} invalid={}", valid, invalid);
}

use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    New,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

#[derive(Clone, Debug)]
struct Ticket {
    owner: String,
    status: Status,
    invalid: u32,
}

fn apply_event(ticket: &mut Ticket, event: &str) {
    let mut parts = event.split(':');
    let kind = parts.next().unwrap();
    let arg = parts.next();

    match kind {
        "assign" => {
            if let Some(name) = arg {
                ticket.owner = name.to_string();
            } else {
                ticket.invalid += 1;
            }
        }
        "start" => {
            ticket.status = Status::InProgress;
        }
        "block" => {
            if ticket.status == Status::InProgress {
                ticket.status = Status::Blocked;
            } else {
                ticket.invalid += 1;
            }
        }
        "resume" => {
            if ticket.status == Status::Blocked {
                ticket.status = Status::Resolved;
            } else {
                ticket.invalid += 1;
            }
        }
        "resolve" => {
            ticket.status = Status::Resolved;
        }
        "close" => {
            if ticket.status == Status::Resolved || ticket.status == Status::New {
                ticket.status = Status::Closed;
            } else {
                ticket.invalid += 1;
            }
        }
        _ => ticket.invalid += 1,
    }
}

fn status_name(s: Status) -> &'static str {
    match s {
        Status::New => "New",
        Status::InProgress => "InProgress",
        Status::Blocked => "Blocked",
        Status::Resolved => "Resolved",
        Status::Closed => "Closed",
    }
}

fn main() {
    let input = [
        "T1 assign:alice",
        "T1 start",
        "T1 resolve",
        "T1 close",
        "T2 close",
        "T2 assign:bob",
        "T2 start",
        "T2 block",
        "T2 resume",
        "T2 assign:carol",
        "T2 close",
        "T3 start",
        "T3 assign:dana",
        "T3 block",
        "T3 resolve",
        "T3 reopen",
    ];

    let mut tickets: BTreeMap<String, Ticket> = BTreeMap::new();

    for line in input {
        let mut sp = line.splitn(2, ' ');
        let id = sp.next().unwrap();
        let event = sp.next().unwrap();
        let ticket = tickets.entry(id.to_string()).or_insert(Ticket {
            owner: "unassigned".to_string(),
            status: Status::New,
            invalid: 0,
        });
        apply_event(ticket, event);
    }

    let mut out = Vec::new();
    for (id, ticket) in tickets {
        let active = matches!(ticket.status, Status::New | Status::InProgress | Status::Blocked) as u8;
        let closed = (ticket.status == Status::Closed) as u8;
        out.push(format!(
            "{}|{}|owner={}|active={}|closed={}|invalid={}",
            id,
            status_name(ticket.status),
            ticket.owner,
            active,
            closed,
            ticket.invalid
        ));
    }

    println!("{}", out.join("\n"));
}

