#[derive(Clone, Copy)]
struct Booking {
    id: &'static str,
    room: &'static str,
    start: u32,
    end: u32,
}

fn fmt_time(m: u32) -> String {
    format!("{:02}:{:02}", m / 60, m % 60)
}

fn overlaps(a: Booking, b: Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn main() {
    let bookings = [
        Booking { id: "A", room: "room1", start: 9 * 60, end: 10 * 60 },
        Booking { id: "B", room: "room1", start: 10 * 60, end: 11 * 60 },
        Booking { id: "C", room: "room1", start: 9 * 60 + 45, end: 10 * 60 + 15 },
        Booking { id: "D", room: "room2", start: 9 * 60 + 30, end: 10 * 60 + 30 },
        Booking { id: "E", room: "room2", start: 10 * 60 + 30, end: 11 * 60 },
        Booking { id: "F", room: "room1", start: 11 * 60, end: 12 * 60 },
        Booking { id: "G", room: "room3", start: 9 * 60 + 15, end: 9 * 60 + 45 },
        Booking { id: "H", room: "room3", start: 9 * 60 + 45, end: 10 * 60 },
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut conflicts: Vec<(Booking, Booking)> = Vec::new();

    for booking in bookings {
        let mut blocked_by = None;
        for existing in &accepted {
            if overlaps(*existing, booking) {
                blocked_by = Some(*existing);
                break;
            }
        }
        if let Some(existing) = blocked_by {
            conflicts.push((booking, existing));
        } else {
            accepted.push(booking);
        }
    }

    let mut out = String::new();
    out.push_str("accepted:\n");
    for b in &accepted {
        out.push_str(&format!(
            "{} {}-{} {}\n",
            b.id,
            fmt_time(b.start),
            fmt_time(b.end),
            b.room
        ));
    }
    out.push_str("conflicts:\n");
    for (b, existing) in &conflicts {
        out.push_str(&format!(
            "{} conflicts with {} in {}\n",
            b.id, existing.id, b.room
        ));
    }

    print!("{}", out.trim_end());
}

