use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, Eq, PartialEq, Ord, PartialOrd)]
enum State {
    Active,
    Pending,
    Suspended,
    Closed,
    Reopened,
}

#[derive(Clone, Copy)]
enum Event {
    Create,
    Defer,
    Suspend,
    Resume,
    Resolve,
    Reopen,
}

fn apply_event(state: Option<State>, event: Event) -> (Option<State>, bool) {
    match (state, event) {
        (None, Event::Create) => (Some(State::Active), true),
        (Some(State::Active), Event::Defer) => (Some(State::Pending), true),
        (Some(State::Pending), Event::Resume) => (Some(State::Active), true),
        (Some(State::Active), Event::Suspend) => (Some(State::Suspended), true),
        (Some(State::Suspended), Event::Resume) => (Some(State::Active), true),
        (Some(State::Active), Event::Resolve) => (Some(State::Closed), true),
        (Some(State::Pending), Event::Resolve) => (Some(State::Closed), true),
        (Some(State::Closed), Event::Reopen) => (Some(State::Active), true),
        // bugs: invalid transitions currently mutate state and reopen loses history
        (Some(State::Closed), Event::Resolve) => (Some(State::Closed), false),
        (_, Event::Reopen) => (Some(State::Active), false),
        (_, _) => (Some(State::Pending), false),
    }
}

fn label(state: State) -> &'static str {
    match state {
        State::Active => "active",
        State::Pending => "pending",
        State::Suspended => "suspended",
        State::Closed => "closed",
        State::Reopened => "reopened",
    }
}

fn main() {
    let scenarios: [(&str, &[Event]); 4] = [
        ("A", &[Event::Create, Event::Defer, Event::Resume, Event::Resolve]),
        ("B", &[Event::Create, Event::Suspend, Event::Resume, Event::Resolve, Event::Reopen]),
        ("C", &[Event::Create, Event::Resolve, Event::Resolve]),
        ("D", &[Event::Create, Event::Suspend, Event::Defer, Event::Resume]),
    ];

    let mut counts: BTreeMap<State, usize> = BTreeMap::new();
    let mut invalid = 0usize;

    for (_id, events) in scenarios {
        let mut state = None;
        for &event in events {
            let (next, ok) = apply_event(state, event);
            state = next;
            if !ok {
                invalid += 1;
            }
        }
        if let Some(s) = state {
            *counts.entry(s).or_insert(0) += 1;
        }
    }

    let ordered = [
        State::Active,
        State::Closed,
        State::Pending,
        State::Suspended,
        State::Reopened,
    ];

    for state in ordered {
        println!("{}: {}", label(state), counts.get(&state).copied().unwrap_or(0));
    }
    println!("invalid transitions: {}", invalid);
}

steps.find:
fn apply_event(state: Option<State>, event: Event) -> (Option<State>, bool) {
    match (state, event) {
        (None, Event::Create) => (Some(State::Active), true),
        (Some(State::Active), Event::Defer) => (Some(State::Pending), true),
        (Some(State::Pending), Event::Resume) => (Some(State::Active), true),
        (Some(State::Active), Event::Suspend) => (Some(State::Suspended), true),
        (Some(State::Suspended), Event::Resume) => (Some(State::Active), true),
        (Some(State::Active), Event::Resolve) => (Some(State::Closed), true),
        (Some(State::Pending), Event::Resolve) => (Some(State::Closed), true),
        (Some(State::Closed), Event::Reopen) => (Some(State::Active), true),
        // bugs: invalid transitions currently mutate state and reopen loses history
        (Some(State::Closed), Event::Resolve) => (Some(State::Closed), false),
        (_, Event::Reopen) => (Some(State::Active), false),
        (_, _) => (Some(State::Pending), false),
    }
}

