pub struct Config {
    pub host: String,
    pub port: u16,
    pub log_level: String,
    pub use_tls: bool,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub log_level: Option<String>,
    pub use_tls: Option<bool>,
}

pub fn merge_config(defaults: &Config, file: &PartialConfig, env: &PartialConfig) -> Config {
    let mut merged = defaults.clone();

    if let Some(host) = &env.host {
        merged.host = host.clone();
    } else if let Some(host) = &file.host {
        merged.host = host.clone();
    }

    if let Some(port) = file.port {
        merged.port = port;
    }
    if let Some(port) = env.port {
        merged.port = port;
    }

    if let Some(level) = &env.log_level {
        merged.log_level = level.clone();
    }

    if let Some(tls) = env.use_tls {
        merged.use_tls = tls;
    } else if let Some(tls) = file.use_tls {
        merged.use_tls = tls;
    }

    merged
}

