use std::cmp::Ordering;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub player: &'static str,
    pub wins: u32,
    pub losses: u32,
    pub points_for: i32,
    pub points_against: i32,
}

impl Entry {
    fn win_pct(&self) -> f32 {
        let games = self.wins + self.losses;
        if games == 0 {
            0.0
        } else {
            self.wins as f32 / games as f32
        }
    }

    fn point_diff(&self) -> i32 {
        self.points_for - self.points_against
    }
}

pub fn leaderboard(entries: &[Entry]) -> Vec<String> {
    let mut rows = entries.to_vec();
    rows.sort_by(|a, b| {
        b.win_pct()
            .partial_cmp(&a.win_pct())
            .unwrap_or(Ordering::Equal)
            .then_with(|| a.point_diff().cmp(&b.point_diff()))
            .then_with(|| a.player.cmp(b.player))
    });

    rows.into_iter()
        .enumerate()
        .map(|(i, e)| format!("{}. {} [{}-{}]", i + 1, e.player, e.wins, e.losses))
        .collect()
}

