pub fn leaderboard(entries: &[Entry]) -> Vec<String> {
    let mut rows = entries.to_vec();
    rows.sort_by(|a, b| {
        let a_key = (a.wins + a.losses == 0, a.win_pct(), a.point_diff(), a.player);
        let b_key = (b.wins + b.losses == 0, b.win_pct(), b.point_diff(), b.player);

        a_key.0.cmp(&b_key.0)
            .then_with(|| b_key.1.partial_cmp(&a_key.1).unwrap_or(Ordering::Equal))
            .then_with(|| a_key.0.then(Ordering::Equal).unwrap_or_else(|| b_key.2.cmp(&a_key.2)))
            .then_with(|| a.player.cmp(b.player))
    });

    let mut out = Vec::with_capacity(rows.len());
    let mut last: Option<(bool, u32, u32, i32)> = None;

    for (i, e) in rows.into_iter().enumerate() {
        let key = (e.wins + e.losses == 0, e.wins, e.losses, e.point_diff());
        let rank = if let Some(prev) = last {
            if prev == key { i } else { i + 1 }
        } else {
            1
        };
        last = Some(key);
        out.push(format!("{}. {} [{}-{}]", rank, e.player, e.wins, e.losses));
    }

    out
