use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Order<'a> {
    pub region: &'a str,
    pub amount_cents: u32,
    pub finalized: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RegionReport {
    pub region: String,
    pub completed_orders: usize,
    pub pending_orders: usize,
    pub total_cents: u32,
    pub average_cents: u32,
}

pub fn build_region_report(orders: &[Order<'_>]) -> Vec<RegionReport> {
    let mut grouped: BTreeMap<&str, (usize, usize, u32)> = BTreeMap::new();

    for order in orders {
        let entry = grouped.entry(order.region).or_insert((0, 0, 0));
        if order.finalized {
            entry.0 += 1;
        } else {
            entry.1 += 1;
        }
        entry.2 += order.amount_cents;
    }

    grouped
        .into_iter()
        .map(|(region, (completed_orders, pending_orders, total_cents))| RegionReport {
            region: region.to_string(),
            completed_orders,
            pending_orders,
            total_cents,
            average_cents: if completed_orders == 0 {
                total_cents
            } else {
                total_cents / completed_orders as u32
            },
        })
        .collect()
}

#[cfg(test)]
