    pub debug: bool,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub debug: Option<bool>,
}

pub fn merge_config(
    defaults: &Config,
    file: Option<&PartialConfig>,
    env: Option<&PartialConfig>,
    cli: Option<&PartialConfig>,
) -> Config {
    let mut out = defaults.clone();

    if let Some(f) = file {
        if let Some(host) = &f.host {
            out.host = host.clone();
        }
        if let Some(port) = f.port {
            out.port = port;
        }
        if let Some(debug) = f.debug {
            out.debug = debug;
        }
    }

    if let Some(c) = cli {
        if let Some(host) = &c.host {
            out.host = host.clone();
        }
        if let Some(port) = c.port {
            out.port = port;
        }
        if let Some(debug) = c.debug {
            out.debug = debug;
        }
    }

    if let Some(e) = env {
        if let Some(host) = &e.host {
            out.host = host.clone();
        }
        if let Some(port) = e.port {
            out.port = port;
        }
        if let Some(debug) = e.debug {
            out.debug = debug;
        }
    }

    out
}

