use std::collections::HashMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub name: &'static str,
    pub wins: u32,
    pub goal_diff: i32,
    pub scored: u32,
}

pub fn leaderboard(entries: &[Entry]) -> Vec<&'static str> {
    let mut best_by_name: HashMap<&'static str, Entry> = HashMap::new();

    for entry in entries {
        best_by_name
            .entry(entry.name)
            .and_modify(|best| {
                if entry.wins > best.wins {
                    *best = entry.clone();
                }
            })
            .or_insert_with(|| entry.clone());
    }

    let mut rows: Vec<Entry> = best_by_name.into_values().collect();
    rows.sort_by(|a, b| {
        b.wins
            .cmp(&a.wins)
            .then_with(|| a.name.cmp(&b.name))
    });

    rows.into_iter().map(|e| e.name).collect()
}

