pub fn extract_visible_values(entries: &[&str]) -> Vec<String> {
    entries
        .iter()
        .filter_map(|entry| {
            let (name, value) = entry.split_once('=')?;
            let name = name.trim();
            let value = value.trim();

            if name.is_empty() || value.is_empty() || name.starts_with('_') {
                return None;
            }

            Some(format!("{}={}", name, value))
        })
        .collect()
}

