#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    New,
    Active,
    Paused,
    Done,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Pause,
    Resume,
    Complete,
    Close,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::New;

    for event in events {
        status = match (status, event) {
            (Status::New, Event::Start) => Status::Active,
            (Status::Active, Event::Pause) => Status::Paused,
            (Status::Paused, Event::Resume) => Status::Active,
            (Status::Active, Event::Complete) => Status::Done,
            (Status::Paused, Event::Complete) => Status::Done,
            (_, Event::Close) => Status::Closed,
            (s, _) => s,
        };
    }

    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event::*, Status};

    #[test]
    fn basic_progression_reaches_done() {
        assert_eq!(apply_events(&[Start, Complete]), Status::Done);
    }

    #[test]
    fn pause_then_resume_then_complete() {
        assert_eq!(apply_events(&[Start, Pause, Resume, Complete]), Status::Done);
    }

    #[test]
    fn close_requires_terminal_state() {
        assert_eq!(apply_events(&[Close]), Status::New);
        assert_eq!(apply_events(&[Start, Close]), Status::Active);
        assert_eq!(apply_events(&[Start, Complete, Close]), Status::Closed);
    }

    #[test]
    fn closed_state_is_terminal() {
        assert_eq!(apply_events(&[Start, Complete, Close, Resume, Start]), Status::Closed);
    }

    #[test]
    fn completed_workflow_cannot_reopen() {
        assert_eq!(apply_events(&[Start, Complete, Resume, Start]), Status::Done);
    }
}

