#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Booking {
    pub room: &'static str,
    pub start: u32,
    pub end: u32,
}

impl Booking {
    pub fn new(room: &'static str, start: u32, end: u32) -> Self {
        Self { room, start, end }
    }
}

pub fn can_book(existing: &[Booking], candidate: &Booking) -> bool {
    if candidate.start >= candidate.end {
        return false;
    }

    !existing.iter().any(|b| {
        if b.room != candidate.room {
            return false;
        }
        candidate.start <= b.end && b.start <= candidate.end
    })
}

