    pub dept: &'static str,
    pub open_count: usize,
    pub total_amount: u32,
}

pub fn summarize(tasks: &[Task]) -> Vec<DeptSummary> {
    let mut names: Vec<&'static str> = Vec::new();
    for task in tasks {
        if !names.contains(&task.dept) {
            names.push(task.dept);
        }
    }
    names.sort();

    let mut out = Vec::new();
    for dept in names {
        let mut open_count = 0;
        let mut total_amount = 0;
        for task in tasks {
            if task.dept == dept {
                open_count += 1;
                total_amount += task.amount;
            }
        }
        if open_count > 0 {
            out.push(DeptSummary {
                dept,
                open_count,
                total_amount,
            });
        }
    }
    out
