#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Method {
    Get,
    Post,
    Delete,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Role {
    Guest,
    User,
    Admin,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Target {
    Health,
    Profile,
    AdminPanel,
    Item(u32),
}

pub fn route_action(method: Method, role: Role, target: Target) -> &'static str {
    match (method, role, target) {
        (Method::Get, _, Target::Health) => "read_public",
        (Method::Get, _, Target::Profile) => "read_own_profile",
        (Method::Post, Role::User, Target::Profile) => "update_profile",
        (Method::Post, _, Target::Item(_)) => "create_item",
        (Method::Delete, Role::Admin, Target::Item(_)) => "delete_any_item",
        (Method::Delete, _, Target::AdminPanel) => "deny",
        (Method::Get, _, Target::AdminPanel) => "read_admin_panel",
        _ => "deny",
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn guest_can_only_read_health() {
        assert_eq!(route_action(Method::Get, Role::Guest, Target::Health), "read_public");
        assert_eq!(route_action(Method::Get, Role::Guest, Target::Profile), "deny");
        assert_eq!(route_action(Method::Get, Role::Guest, Target::AdminPanel), "deny");
        assert_eq!(route_action(Method::Post, Role::Guest, Target::Item(7)), "deny");
    }

    #[test]
    fn user_profile_access_depends_on_method() {
        assert_eq!(route_action(Method::Get, Role::User, Target::Profile), "read_own_profile");
        assert_eq!(route_action(Method::Post, Role::User, Target::Profile), "update_profile");
        assert_eq!(route_action(Method::Delete, Role::User, Target::Profile), "deny");
    }

    #[test]
    fn only_admin_can_reach_admin_panel() {
        assert_eq!(route_action(Method::Get, Role::Admin, Target::AdminPanel), "read_admin_panel");
        assert_eq!(route_action(Method::Delete, Role::Admin, Target::AdminPanel), "deny");
        assert_eq!(route_action(Method::Get, Role::User, Target::AdminPanel), "deny");
    }

    #[test]
    fn item_actions_split_by_role_and_method() {
        assert_eq!(route_action(Method::Post, Role::User, Target::Item(1)), "create_item");
        assert_eq!(route_action(Method::Post, Role::Admin, Target::Item(1)), "create_item");
        assert_eq!(route_action(Method::Post, Role::Guest, Target::Item(1)), "deny");
        assert_eq!(route_action(Method::Delete, Role::Admin, Target::Item(1)), "delete_any_item");
        assert_eq!(route_action(Method::Delete, Role::User, Target::Item(1)), "deny");
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct PartialConfig {
    pub endpoint: Option<String>,
    pub token: Option<String>,
    pub retries: Option<u32>,
    pub verbose: Option<bool>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct EffectiveConfig {
    pub endpoint: String,
    pub token: String,
    pub retries: u32,
    pub verbose: bool,
}

fn choose_string(high: Option<String>, low: Option<String>, fallback: &str) -> String {
    high.or(low).unwrap_or_else(|| fallback.to_string())
}

fn choose_u32(high: Option<u32>, low: Option<u32>, fallback: u32) -> u32 {
    high.or(low).unwrap_or(fallback)
}

fn choose_bool(high: Option<bool>, low: Option<bool>, fallback: bool) -> bool {
    high.unwrap_or(low.unwrap_or(fallback))
}

pub fn merge_config(
    defaults: PartialConfig,
    file: PartialConfig,
    env: PartialConfig,
    cli: PartialConfig,
) -> EffectiveConfig {
    EffectiveConfig {
        endpoint: choose_string(defaults.endpoint, file.endpoint.or(env.endpoint), "https://localhost"),
        token: choose_string(defaults.token, file.token.or(env.token).or(cli.token), ""),
        retries: choose_u32(cli.retries, env.retries.or(file.retries).or(defaults.retries), 3),
        verbose: choose_bool(defaults.verbose, file.verbose.or(env.verbose).or(cli.verbose), false),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn cfg(
        endpoint: Option<&str>,
        token: Option<&str>,
        retries: Option<u32>,
        verbose: Option<bool>,
    ) -> PartialConfig {
        PartialConfig {
            endpoint: endpoint.map(str::to_string),
            token: token.map(str::to_string),
            retries,
            verbose,
        }
    }

    #[test]
    fn precedence_is_cli_then_env_then_file_then_defaults() {
        let defaults = cfg(Some("https://default"), Some("default-token"), Some(2), Some(false));
        let file = cfg(Some("https://file"), Some("file-token"), Some(4), Some(false));
        let env = cfg(Some("https://env"), Some("env-token"), Some(6), Some(true));
        let cli = cfg(Some("https://cli"), Some("cli-token"), Some(8), Some(false));

        let merged = merge_config(defaults, file, env, cli);

        assert_eq!(
            merged,
            EffectiveConfig {
                endpoint: "https://cli".to_string(),
                token: "cli-token".to_string(),
                retries: 8,
                verbose: false,
            }
        );
    }

    #[test]
    fn empty_high_precedence_strings_do_not_block_lower_values() {
        let defaults = cfg(Some("https://default"), Some("default-token"), Some(2), Some(false));
        let file = cfg(Some(""), Some("file-token"), None, None);
        let env = cfg(Some("https://env"), Some(""), None, None);
        let cli = cfg(Some(""), None, None, None);

        let merged = merge_config(defaults, file, env, cli);

        assert_eq!(merged.endpoint, "https://env");
        assert_eq!(merged.token, "file-token");
        assert_eq!(merged.retries, 2);
        assert!(!merged.verbose);
    }

    #[test]
    fn explicit_false_overrides_lower_true() {
        let defaults = cfg(None, None, None, Some(true));
        let file = cfg(None, None, None, Some(true));
        let env = cfg(None, None, None, Some(true));
        let cli = cfg(None, None, None, Some(false));

        let merged = merge_config(defaults, file, env, cli);
        assert!(!merged.verbose);
    }

    #[test]
    fn defaults_and_fallbacks_apply_when_layers_missing() {
        let defaults = cfg(None, None, Some(5), None);
        let file = cfg(None, None, None, None);
        let env = cfg(None, None, None, None);
        let cli = cfg(None, None, None, None);

        let merged = merge_config(defaults, file, env, cli);

        assert_eq!(merged.endpoint, "https://localhost");
        assert_eq!(merged.token, "");
        assert_eq!(merged.retries, 5);
        assert!(!merged.verbose);
    }
}

