#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    OnHold,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Hold,
    Resume,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    use Event::*;
    use Status::*;

    match (status, event) {
        (Open, Start) => InProgress,
        (Open, Close) => Closed,
        (InProgress, Hold) => OnHold,
        (InProgress, Resolve) => Resolved,
        (OnHold, Resume) => InProgress,
        (OnHold, Resolve) => Resolved,
        (Resolved, Close) => Closed,
        (Resolved, Reopen) => Open,
        (Closed, Reopen) => Open,
        _ => status,
    }
}

pub fn apply_events(initial: Status, events: &[Event]) -> Status {
    events.iter().copied().fold(initial, apply_event)
}

#[cfg(test)]
mod tests {
    use super::{apply_event, apply_events, Event::*, Status::*};

    #[test]
    fn hold_and_resume_cycle() {
        let final_state = apply_events(Open, &[Start, Hold, Resume, Resolve, Close]);
        assert_eq!(final_state, Closed);
    }

    #[test]
    fn invalid_events_leave_state_unchanged() {
        assert_eq!(apply_event(Open, Resume), Open);
        assert_eq!(apply_event(Closed, Hold), Closed);
        assert_eq!(apply_event(Resolved, Start), Resolved);
    }

    #[test]
    fn reopen_from_closed_requires_work_before_closing() {
        let final_state = apply_events(Open, &[Start, Resolve, Close, Reopen, Close]);
        assert_eq!(final_state, Open);
    }

    #[test]
    fn reopen_then_process_again() {
        let final_state = apply_events(Open, &[Start, Resolve, Reopen, Start, Hold, Resume, Resolve]);
        assert_eq!(final_state, Resolved);
    }

    #[test]
    fn resolving_from_hold_skips_resume() {
        let final_state = apply_events(Open, &[Start, Hold, Resolve]);
        assert_eq!(final_state, Resolved);
    }
}

