fn classify(line: &str) -> String {
    let trimmed = line.trim();
    if trimmed.is_empty() {
        return "skip".to_string();
    }

    let Some((key, value)) = trimmed.split_once('=') else {
        return format!("bad:{} reason=missing_equals", trimmed);
    };

    let key = key.trim();
    let value = value.trim();

    if key.is_empty() {
        return format!("bad:{} reason=empty_key", trimmed);
    }
    if value.parse::<u32>().is_err() {
        return format!("bad:{} reason=non_numeric_value", key);
    }

    format!("ok:{}={}", key, value)
}

fn main() {
    let input = "alice=42
bob=7
charlie=oops
 =5
eve
";

    let mut out = Vec::new();
    let mut valid = 0usize;
    let mut invalid = 0usize;

    for line in input.lines() {
        let status = classify(line);
        if status == "skip" {
            continue;
        }
        if status.starts_with("ok:") {
            valid += 1;
        } else {
            invalid += 1;
        }
        out.push(status);
    }

    println!("valid={} invalid={}", valid, invalid);
    for line in out {
        println!("{}", line);
    }
}

use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum State {
    New,
    InProgress,
    Blocked,
    Closed,
}

enum Event<'a> {
    Create(&'a str),
    Start(&'a str),
    Block(&'a str),
    Unblock(&'a str),
    Resolve(&'a str),
    Reopen(&'a str),
}

fn apply(state: Option<State>, event: &Event<'_>) -> Option<State> {
    use Event::*;
    use State::*;

    match (state, event) {
        (None, Create(_)) => Some(New),
        (Some(New), Start(_)) => Some(InProgress),
        (Some(InProgress), Block(_)) => Some(Blocked),
        (Some(Blocked), Unblock(_)) => Some(InProgress),
        (Some(InProgress), Resolve(_)) | (Some(Blocked), Resolve(_)) => Some(Closed),
        (Some(Closed), Reopen(_)) => Some(InProgress),
        (s, _) => s,
    }
}

fn ticket_id(event: &Event<'_>) -> &str {
    match event {
        Event::Create(id)
        | Event::Start(id)
        | Event::Block(id)
        | Event::Unblock(id)
        | Event::Resolve(id)
        | Event::Reopen(id) => id,
    }
}

fn label(state: State) -> &'static str {
    match state {
        State::New => "new",
        State::InProgress => "in_progress",
        State::Blocked => "blocked",
        State::Closed => "closed",
    }
}

fn main() {
    let events = [
        Event::Create("T1"),
        Event::Resolve("T1"),
        Event::Start("T1"),
        Event::Resolve("T1"),
        Event::Create("T2"),
        Event::Start("T2"),
        Event::Block("T2"),
        Event::Unblock("T2"),
        Event::Create("T3"),
        Event::Start("T3"),
        Event::Resolve("T3"),
        Event::Reopen("T3"),
        Event::Resolve("T3"),
        Event::Block("T1"),
    ];

    let mut states: BTreeMap<&str, State> = BTreeMap::new();
    for event in &events {
        let id = ticket_id(event);
        let next = apply(states.get(id).copied(), event);
        if let Some(state) = next {
            states.insert(id, state);
        }
    }

    let mut out = Vec::new();
    for (id, state) in states {
        out.push(format!("{}={}", id, label(state)));
    }
    print!("{}", out.join("\n"));
}
